export enum PatientStatus {
  WAITING_ADMISSION = 'En attente accueil',
  WAITING_TRIAGE = 'En attente triage',
  IN_CONSULTATION = 'En consultation',
  WAITING_LAB = 'En attente Labo',
  INPATIENT = 'Hospitalisé',
  IN_MATERNITY = 'En Maternité',
  DISCHARGED = 'Sorti'
}

export enum Role {
  RECEPTION = 'ACCUEIL',
  DOCTOR = 'MEDECIN',
  NURSE = 'INFIRMIER',
  LAB = 'LABO',
  PHARMACY = 'PHARMACIE',
  CASHIER = 'CAISSE',
  ADMIN = 'ADMIN'
}

export interface Patient {
  id: string;
  firstName: string;
  lastName: string;
  birthDate: string;
  gender: 'M' | 'F';
  phone: string;
  bloodGroup?: string;
  allergies?: string[];
  lastVisit?: string;
  isNewborn?: boolean;
  motherId?: string;
}

export interface Medication {
  id: string;
  name: string;
  stockLevel: number;
  unit: string;
  price: number;
  expiryDate: string;
  batchNumber: string;
  minThreshold: number;
}

export interface Invoice {
  id: string;
  patientId: string;
  items: Array<{
    description: string;
    amount: number;
    category: 'CONSULTATION' | 'LAB' | 'PHARMACY' | 'HOSPITALIZATION' | 'MATERNITY';
  }>;
  total: number;
  status: 'UNPAID' | 'PAID';
  timestamp: string;
  cashierId: string;
}

export interface MaternityRecord {
  patientId: string;
  lastMenstrualPeriod: string;
  expectedDueDate: string;
  gravidity: number;
  parity: number;
  cpnHistory: Array<{
    date: string;
    weight: number;
    bp: string;
    fetalHeartRate: number;
    notes: string;
  }>;
  partogram?: {
    startTime: string;
    entries: Array<{
      time: string;
      dilation: number; // 0-10cm
      station: number; // -3 to +3
      contractions: number; // per 10 mins
    }>;
  };
}

export interface StaffMember {
  id: string;
  name: string;
  role: Role;
  specialty?: string;
  quotePartRate: number; // percentage
  accumulatedFees: number;
  lastLogin: string;
}

import React, { useState } from 'react';
import { Role } from './types';
import Sidebar from './components/Sidebar';
import Dashboard from './pages/Dashboard';
import Reception from './pages/Reception';
import Consultation from './pages/Consultation';
import Inpatient from './pages/Inpatient';
import Lab from './pages/Lab';
import Maternity from './pages/Maternity';
import Pharmacy from './pages/Pharmacy';
import Accounting from './pages/Accounting';
import Personnel from './pages/Personnel';

const App: React.FC = () => {
  const [currentRole, setCurrentRole] = useState<Role>(Role.ADMIN);

  const renderPage = () => {
    switch(currentRole) {
      case Role.ADMIN: return <Dashboard />;
      case Role.RECEPTION: return <Reception />;
      case Role.DOCTOR: return <Consultation />;
      case Role.NURSE: return <Inpatient />;
      case Role.LAB: return <Lab />;
      case Role.PHARMACY: return <Pharmacy />;
      case Role.CASHIER: return <Accounting />;
      // En l'absence de rôle spécifique pour la Maternité ou le Personnel dans l'énumération de base, 
      // on peut utiliser l'admin ou étendre le switch.
      default: 
        if ((currentRole as string) === 'MATERNITY') return <Maternity />;
        return <Dashboard />;
    }
  };

  // Extension temporaire pour la démo des nouveaux modules
  const handleNav = (role: Role) => {
    setCurrentRole(role);
  };

  return (
    <div className="min-h-screen bg-slate-50 flex">
      {/* Sidebar passée avec un setter de rôle plus flexible */}
      <Sidebar currentRole={currentRole} setRole={handleNav} />

      <main className="flex-1 ml-64 min-h-screen relative">
        <div className="max-w-[1600px] mx-auto">
          {/* Section de navigation rapide pour les nouveaux modules non encore présents dans la sidebar standard */}
          <div className="px-8 pt-4 flex gap-2">
             <button onClick={() => setCurrentRole(Role.PHARMACY)} className="px-3 py-1 bg-white border rounded-lg text-[10px] font-bold text-slate-400 hover:text-emerald-600 transition-colors">PHARMACIE</button>
             <button onClick={() => setCurrentRole(Role.CASHIER)} className="px-3 py-1 bg-white border rounded-lg text-[10px] font-bold text-slate-400 hover:text-blue-600 transition-colors">CAISSE / COMPTA</button>
             <button onClick={() => setCurrentRole('MATERNITY' as any)} className="px-3 py-1 bg-white border rounded-lg text-[10px] font-bold text-slate-400 hover:text-pink-600 transition-colors">MATERNITÉ</button>
             <button onClick={() => setCurrentRole(Role.ADMIN)} className="px-3 py-1 bg-white border rounded-lg text-[10px] font-bold text-slate-400 hover:text-slate-900 transition-colors">PERSONNEL (Via Admin)</button>
          </div>

          {renderPage()}

          {/* Inject Personnel dashboard as a subset of Admin for now if needed */}
          {currentRole === Role.ADMIN && (
            <div className="mt-8 border-t border-slate-200">
               <Personnel />
            </div>
          )}
        </div>

        <div className="fixed bottom-8 right-8 z-50 pointer-events-none">
          <div className="space-y-3 flex flex-col items-end">
            <div className="bg-slate-900 text-white px-6 py-4 rounded-2xl shadow-2xl flex items-center gap-4 pointer-events-auto border border-slate-800">
              <div className="w-2 h-2 bg-emerald-500 rounded-full animate-pulse"></div>
              <div>
                <p className="text-[10px] font-black uppercase text-slate-500">Stock</p>
                <p className="text-xs font-bold">Pharmacie: Vente de Paracétamol validée (-1 boîte)</p>
              </div>
            </div>
          </div>
        </div>
      </main>
    </div>
  );
};

export default App;
